import { Col, DatePicker, Input, Modal, Row, Select } from "antd"
import dayjs from "dayjs"
import isBetween from "dayjs/plugin/isBetween"
import { useEffect, useState } from "react"
import { FloatActionWrapper } from "src/components/FloatAction/styles"
import InputCustom from "src/components/Input/InputCustom"
import CB1 from "src/components/Modal/CB1"
import ButtonCustom from "src/components/MyButton/Button"
import ButtonCircle from "src/components/MyButton/ButtonCircle"
import notice from "src/components/Notice"
import SpinCustom from "src/components/SpinCustom"
import TableCustom from "src/components/Table/CustomTable"
import {
  MainTableData,
  SubTableData,
} from "src/components/Table/CustomTable/styled"
import TitleCustom from "src/components/TitleCustom"
import { hideOnSinglePage } from "src/constants/constants"
import AssociationService from "src/services/AssociationService"
import AssociationDetailModal from "./Modal/AssociationDetailModal"
import "./style.scss"

dayjs.extend(isBetween)

const AssociationApproval = () => {
  const [fromDate, setFromDate] = useState(null)
  const [toDate, setToDate] = useState(null)
  const [textSearch, setTextSearch] = useState("")
  const [statusFilter, setStatusFilter] = useState(null)
  const [pagination, setPagination] = useState({ pageSize: 10, currentPage: 1 })
  const [loading, setLoading] = useState(false)
  const [listData, setListData] = useState({ Object: [], Total: 0 })
  const [selectedRowKeys, setSelectedRowKeys] = useState([])
  const [detailModalOpen, setDetailModalOpen] = useState(false)
  const [selectedAssociation, setSelectedAssociation] = useState(null)
  const [reasonModal, setReasonModal] = useState({
    open: false,
    ids: [],
    onConfirm: null,
  })
  const [rejectReason, setRejectReason] = useState("")

  useEffect(() => {
    fetchList()
  }, [
    pagination.currentPage,
    pagination.pageSize,
    textSearch,
    fromDate,
    toDate,
    statusFilter,
  ])

  const fetchList = async () => {
    try {
      setLoading(true)

      const body = {
        PageSize: 9999,
        CurrentPage: 1,
        TextSearch: textSearch,
      }

      const res = await AssociationService.getRequestApproval(body)
      if (res?.isError) {
        notice({
          msg: `Lỗi khi lấy danh sách hiệp hội: ${
            res?.message || "Unknown error"
          }`,
          isSuccess: false,
        })
        setListData({ Object: [], Total: 0 })
        return
      }

      let data = res.Object?.ListData || []

      if (fromDate && toDate) {
        const start = fromDate.startOf("day")
        const end = toDate.endOf("day")
        data = data.filter(item => {
          const date = dayjs(item.EstablishmentDate)
          if (!date.isValid()) return false
          return date.isBetween(start, end, null, "[]")
        })
      }

      if (statusFilter !== null && statusFilter !== undefined) {
        data = data.filter(item => item.Status === statusFilter)
      }

      const startIndex = (pagination.currentPage - 1) * pagination.pageSize
      const endIndex = startIndex + pagination.pageSize
      const pagedData = data.slice(startIndex, endIndex)

      setListData({
        Object: pagedData,
        Total: data.length,
      })
    } catch (error) {
      notice({
        msg: `Lỗi khi lấy danh sách: ${error.message}`,
        isSuccess: false,
      })
    } finally {
      setLoading(false)
    }
  }

  const approveRequests = async associationIDs => {
    try {
      setLoading(true)
      for (let id of associationIDs) {
        const res = await AssociationService.approveRequest(id)
        if (res?.isError) {
          notice({
            msg: res?.message || "Lỗi khi duyệt yêu cầu",
            isSuccess: false,
          })
          return false
        }
      }
      notice({ msg: "Duyệt thành công!" })
      return true
    } catch (error) {
      notice({ msg: `Lỗi hệ thống: ${error.message}`, isSuccess: false })
      return false
    } finally {
      setLoading(false)
    }
  }

  const rejectRequests = async (associationIDs, reason) => {
    try {
      setLoading(true)
      const res = await AssociationService.rejectRequest({
        AssociationIds: associationIDs,
        Reason: reason,
      })
      if (res?.isError) {
        notice({
          msg: res?.message || "Lỗi khi từ chối yêu cầu",
          isSuccess: false,
        })
        return false
      }
      notice({ msg: "Từ chối thành công!" })
      return true
    } catch (error) {
      notice({ msg: `Lỗi hệ thống: ${error.message}`, isSuccess: false })
      return false
    } finally {
      setLoading(false)
    }
  }

  const handleBulkApprove = () => {
    if (selectedRowKeys.length === 0) {
      notice({
        msg: "Vui lòng chọn ít nhất một yêu cầu để chấp nhận.",
        isSuccess: false,
      })
      return
    }
    CB1({
      title: `Bạn có chắc chắn muốn duyệt ${selectedRowKeys.length} yêu cầu?`,
      icon: "check-circle",
      okText: "Đồng ý",
      onOk: async close => {
        const success = await approveRequests(selectedRowKeys)
        if (success) {
          await fetchList()
          setSelectedRowKeys([])
          close()
        }
      },
    })
  }

  const handleBulkReject = () => {
    if (selectedRowKeys.length === 0) {
      notice({
        msg: "Vui lòng chọn ít nhất một yêu cầu để từ chối.",
        isSuccess: false,
      })
      return
    }
    setRejectReason("")
    setReasonModal({
      open: true,
      ids: selectedRowKeys,
      onConfirm: reason => {
        CB1({
          title: `Bạn có chắc chắn muốn từ chối ${selectedRowKeys.length} yêu cầu?`,
          icon: "cancel",
          okText: "Đồng ý",
          onOk: async close => {
            const success = await rejectRequests(selectedRowKeys, reason)
            if (success) {
              await fetchList()
              setSelectedRowKeys([])
              close()
            }
          },
        })
      },
    })
  }

  const handleDateFilterChange = dates => {
    if (dates && dates.length === 2) {
      setFromDate(dates[0])
      setToDate(dates[1])
    } else {
      setFromDate(null)
      setToDate(null)
    }
    setPagination(prev => ({ ...prev, currentPage: 1 }))
  }

  const columns = [
    {
      title: "STT",
      dataIndex: "index",
      key: "index",
      width: 70,
      align: "center",
      render: (_, __, idx) =>
        idx + 1 + pagination.pageSize * (pagination.currentPage - 1),
    },
    {
      title: "Tên hiệp hội",
      dataIndex: "AssociationName",
      key: "AssociationName",
      align: "center",
      render: text => text || "-",
    },
    {
      title: "Mã hiệp hội",
      dataIndex: "AssociationCode",
      key: "AssociationCode",
      align: "center",
      render: text => text || "-",
    },
    {
      title: "Ngày thành lập",
      dataIndex: "EstablishmentDate",
      key: "EstablishmentDate",
      align: "center",
      render: text =>
        text && dayjs(text).isValid() ? dayjs(text).format("DD/MM/YYYY") : "-",
    },
    {
      title: (
        <div>
          <MainTableData>Số điện thoại</MainTableData>
          <SubTableData style={{ color: "white" }}>Email</SubTableData>
        </div>
      ),
      key: "PhoneEmail",
      align: "center",
      render: (_, record) => (
        <div onMouseDown={e => e.stopPropagation()}>
          <MainTableData className="max-line1">
            {record.PhoneNumber || "-"}
          </MainTableData>
          <SubTableData className="fs-13">{record.Email || "-"}</SubTableData>
        </div>
      ),
    },
    {
      title: "Trạng thái",
      dataIndex: "Status",
      key: "StatusAction",
      align: "center",
      render: (text, record) => {
        let statusText = ""
        let statusStyle = {}
        if (text === 2) {
          statusText = "Chờ phê duyệt"
          statusStyle = { color: "#FF8C00", fontWeight: "bold" }
        } else if (text === 3) {
          statusText = "Đang hoạt động"
          statusStyle = { color: "#008000", fontWeight: "bold" }
        } else if (text === 5) {
          statusText = "Bị từ chối duyệt"
          statusStyle = { color: "#FF0000", fontWeight: "bold" }
        }

        return (
          <div className="text-center">
            <div className="max-line2" title={statusText} style={statusStyle}>
              {statusText}
            </div>
            {text === 2 && (
              <FloatActionWrapper
                size="small"
                className="float-action__wrapper"
              >
                <ButtonCircle
                  title="Chấp nhận"
                  iconName="check-circle"
                  style={{
                    background: "#EDF6FC",
                    boxShadow: "0px 2px 4px rgba(208, 206, 187, 0.5)",
                  }}
                  onClick={e => {
                    e.stopPropagation()
                    CB1({
                      title: "Bạn có chắc chắn muốn duyệt không?",
                      icon: "check-circle",
                      okText: "Đồng ý",
                      onOk: async close => {
                        const success = await approveRequests([
                          record.AssociationID,
                        ])
                        if (success) await fetchList()
                        close()
                      },
                    })
                  }}
                />
                <ButtonCircle
                  title="Từ chối"
                  iconName="cancel"
                  style={{
                    background: "#FFE9EC",
                    boxShadow: "0px 2px 4px rgba(208, 206, 187, 0.5)",
                  }}
                  onClick={e => {
                    e.stopPropagation()
                    setRejectReason("")
                    setReasonModal({
                      open: true,
                      ids: [record.AssociationID],
                      onConfirm: reason => {
                        CB1({
                          title: "Bạn có chắc chắn muốn từ chối không?",
                          icon: "cancel",
                          okText: "Đồng ý",
                          onOk: async close => {
                            const success = await rejectRequests(
                              [record.AssociationID],
                              reason,
                            )
                            if (success) await fetchList()
                            close()
                          },
                        })
                      },
                    })
                  }}
                />
              </FloatActionWrapper>
            )}
          </div>
        )
      },
    },
  ]

  return (
    <SpinCustom spinning={loading}>
      <Row
        className="box-action sticky"
        gutter={12}
        style={{ marginBottom: 16 }}
      >
        <Col span={24}>
          <TitleCustom className="d-flex-sb">
            <span>Danh sách hiệp hội</span>
            <div className="d-flex-end">
              <ButtonCustom
                type="primary"
                className="btn-hover-shadow mr-8"
                onClick={handleBulkApprove}
              >
                Chấp nhận
              </ButtonCustom>
              <ButtonCustom
                type="primary"
                className="btn-hover-shadow"
                onClick={handleBulkReject}
              >
                Từ chối
              </ButtonCustom>
            </div>
          </TitleCustom>
        </Col>

        <Col span={12}>
          <InputCustom
            type="search"
            allowClear
            label="Tìm theo tên hiệp hội"
            enterButton
            onChange={e => {
              setTextSearch(e.target.value)
              setPagination(prev => ({ ...prev, currentPage: 1 }))
            }}
          />
        </Col>

        <Col span={8}>
          <DatePicker.RangePicker
            style={{ width: "100%" }}
            format="DD/MM/YYYY"
            allowClear
            value={fromDate && toDate ? [fromDate, toDate] : []}
            onChange={handleDateFilterChange}
            placeholder={["Từ ngày", "Đến ngày"]}
          />
        </Col>

        <Col span={4}>
          <Select
            allowClear
            style={{ width: "100%" }}
            placeholder="Trạng thái"
            value={statusFilter}
            onChange={value => {
              setStatusFilter(value)
              setPagination(prev => ({ ...prev, currentPage: 1 }))
            }}
            options={[
              { label: "Chờ phê duyệt", value: 2 },
              { label: "Đang hoạt động", value: 3 },
              { label: "Bị từ chối duyệt", value: 5 },
            ]}
          />
        </Col>
      </Row>

      <TableCustom
        sticky={{ offsetHeader: -12 }}
        columns={columns}
        dataSource={listData.Object}
        textEmpty="Không có dữ liệu"
        rowKey="AssociationID"
        rowSelection={{
          selectedRowKeys,
          onChange: keys => setSelectedRowKeys(keys),
          getCheckboxProps: record => ({ disabled: record.Status !== 2 }),
        }}
        pagination={{
          hideOnSinglePage: listData.Total <= hideOnSinglePage,
          current: pagination.currentPage,
          pageSize: pagination.pageSize,
          total: listData.Total,
          showSizeChanger: listData.Total > pagination.pageSize,
          onChange: (currentPage, pageSize) =>
            setPagination(prev => ({ ...prev, currentPage, pageSize })),
        }}
        onRow={record => ({
          onClick: () => {
            if (window.getSelection().toString()) return
            setSelectedAssociation(record.AssociationID)
            setDetailModalOpen(true)
          },
        })}
      />

      <AssociationDetailModal
        open={detailModalOpen}
        associationId={selectedAssociation}
        onCancel={() => setDetailModalOpen(false)}
        onOk={async () => {
          await fetchList()
          setDetailModalOpen(false)
        }}
      />

      <Modal
        open={reasonModal.open}
        title="Lý do từ chối"
        cancelText="Hủy"
        okText="Chấp nhận"
        onCancel={() =>
          setReasonModal({ open: false, ids: [], onConfirm: null })
        }
        onOk={() => {
          if (!rejectReason.trim()) {
            notice({ msg: "Vui lòng nhập lý do từ chối", isSuccess: false })
            return
          }
          setReasonModal({ ...reasonModal, open: false })
          reasonModal.onConfirm && reasonModal.onConfirm(rejectReason)
        }}
      >
        <Input.TextArea
          rows={4}
          placeholder="Nhập lý do từ chối..."
          value={rejectReason}
          onChange={e => setRejectReason(e.target.value)}
        />
      </Modal>
    </SpinCustom>
  )
}

export default AssociationApproval
