import { useEffect, useState } from "react"
import { Col, Row, Select, Image, Modal, Input } from "antd"
import moment from "moment"
import CustomModal from "src/components/Modal/CustomModal"
import ButtonCustom from "src/components/MyButton/Button"
import notice from "src/components/Notice"
import CB1 from "src/components/Modal/CB1"
import AssociationService from "src/services/AssociationService"
import MemberService from "src/services/MemberService"
import TableCustom from "src/components/Table/CustomTable"
import {
  MainTableData,
  SubTableData,
} from "src/components/Table/CustomTable/styled"
import "./AssociationDetailModal.scss"

const AssociationDetailModal = ({ open, associationId, onCancel, onOk }) => {
  const [detail, setDetail] = useState(null)
  const [modalLoading, setModalLoading] = useState(false)
  const [tableLoading, setTableLoading] = useState(false)
  const [members, setMembers] = useState([])
  const [memberType, setMemberType] = useState(1)

  const [rejectReason, setRejectReason] = useState("")
  const [reasonModalOpen, setReasonModalOpen] = useState(false)

  const fetchDetail = async () => {
    try {
      setModalLoading(true)
      const res = await AssociationService.getAssociationDetail({
        associationId,
      })
      if (res?.isOk) {
        setDetail(res.Object || {})
      } else {
        notice({ msg: "Không tải được chi tiết hiệp hội!", isSuccess: false })
        setDetail({})
      }
    } catch (error) {
      notice({ msg: "Có lỗi khi tải chi tiết hiệp hội!", isSuccess: false })
      setDetail({})
    } finally {
      setModalLoading(false)
    }
  }

  const fetchMembers = async () => {
    try {
      setTableLoading(true)
      const res = await MemberService.getListMember({
        PageSize: 50,
        CurrentPage: 1,
        Status: 1,
        MemberType: memberType,
        AssociationID: associationId,
      })
      if (res?.isOk) {
        const list =
          memberType === 1
            ? res.Object.ListIndividualMembers
            : res.Object.ListOrganizationMembers
        setMembers(list || [])
      } else {
        notice({ msg: "Không tải được danh sách hội viên!", isSuccess: false })
        setMembers([])
      }
    } catch (error) {
      notice({ msg: "Có lỗi khi tải danh sách hội viên!", isSuccess: false })
      setMembers([])
    } finally {
      setTableLoading(false)
    }
  }

  const handleApprove = () => {
    CB1({
      title: "Bạn có chắc chắn muốn duyệt không?",
      icon: "check-circle",
      okText: "Đồng ý",
      onOk: async close => {
        try {
          setModalLoading(true)
          const res = await AssociationService.approveRequest(associationId)
          if (res?.isOk) {
            notice({ msg: "Duyệt thành công!" })
            onOk?.()
            onCancel()
          } else {
            notice({ msg: "Duyệt thất bại!", isSuccess: false })
          }
        } catch (error) {
          notice({ msg: "Có lỗi khi duyệt!", isSuccess: false })
        } finally {
          setModalLoading(false)
          close()
        }
      },
    })
  }

  const handleReject = () => {
    setRejectReason("")
    setReasonModalOpen(true)
  }

  useEffect(() => {
    if (open && associationId) {
      fetchDetail()
      fetchMembers()
    } else {
      setDetail(null)
      setMembers([])
      setMemberType(1)
    }
  }, [open, associationId])

  useEffect(() => {
    if (open && associationId) {
      fetchMembers()
    }
  }, [memberType])

  const memberColumns = [
    {
      title: "STT",
      dataIndex: "index",
      key: "index",
      width: 60,
      align: "center",
      render: (_, __, idx) => <div className="text-center">{idx + 1}</div>,
    },
    {
      title: "Ảnh",
      dataIndex: "Avatar",
      key: "Avatar",
      align: "center",
      width: 80,
      render: (_, record) =>
        record.Avatar ? (
          <div
            style={{
              width: 40,
              height: 40,
              borderRadius: "50%",
              overflow: "hidden",
              position: "relative",
            }}
          >
            <Image
              src={record.Avatar}
              alt="avatar"
              width={40}
              height={40}
              style={{ borderRadius: "50%", objectFit: "cover" }}
              preview={{
                mask: (
                  <div
                    style={{
                      width: 40,
                      height: 40,
                      borderRadius: "50%",
                      background: "rgba(0, 0, 0, 0.45)",
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "center",
                      color: "#fff",
                      fontSize: 12,
                      position: "absolute",
                      top: 0,
                      left: 0,
                    }}
                  >
                    Xem ảnh
                  </div>
                ),
              }}
            />
          </div>
        ) : (
          "Không có"
        ),
    },
    {
      title: (
        <div>
          <MainTableData>Họ và tên</MainTableData>
          <SubTableData style={{ color: "white" }}>Số điện thoại</SubTableData>
        </div>
      ),
      key: "FullNamePhone",
      align: "center",
      render: (_, record) => (
        <div onMouseDown={e => e.stopPropagation()}>
          <MainTableData className="max-line1">
            {record.FullName || record.OrganizationName || "Chưa có thông tin"}
          </MainTableData>
          <SubTableData className="fs-13">
            {record.PhoneNumber || "Chưa có thông tin"}
          </SubTableData>
        </div>
      ),
    },
    {
      title: (
        <div>
          <MainTableData>CCCD/MST</MainTableData>
          <SubTableData style={{ color: "white" }}>Email</SubTableData>
        </div>
      ),
      key: "IdentityEmail",
      align: "center",
      render: (_, record) => (
        <div onMouseDown={e => e.stopPropagation()}>
          <MainTableData className="max-line1">
            {record.Identity || record.TaxCode || "Chưa có thông tin"}
          </MainTableData>
          <SubTableData className="fs-13">
            {record.Email || "Chưa có thông tin"}
          </SubTableData>
        </div>
      ),
    },
    {
      title: (
        <div>
          <MainTableData>Vai trò</MainTableData>
          <SubTableData style={{ color: "white" }}>Loại hội viên</SubTableData>
        </div>
      ),
      key: "RoleType",
      align: "center",
      render: (_, record) => (
        <div onMouseDown={e => e.stopPropagation()}>
          <MainTableData className="max-line1">
            {record.PositionName || record.Position || "Chưa có thông tin"}
          </MainTableData>
          <SubTableData className="fs-13">
            {record.MemberType === 1 || record.MemberType === "1"
              ? "Cá nhân"
              : record.MemberType === 2 || record.MemberType === "2"
              ? "Doanh nghiệp"
              : "Chưa xác định"}
          </SubTableData>
        </div>
      ),
    },
  ]

  const statusMap = {
    2: "Chờ phê duyệt",
    3: "Đang hoạt động",
    5: "Bị từ chối duyệt",
    default: "Không xác định",
  }

  const formatDate = date => {
    if (!date || !moment(date).isValid()) return "Chưa có thông tin"
    return moment(date).format("DD/MM/YYYY")
  }

  const normalizeString = str =>
    str?.trim().replace(/\s+/g, " ") || "Chưa có thông tin"

  const infoData = detail
    ? [
        {
          key: "name",
          label: "Tên hiệp hội",
          value: normalizeString(detail.AssociationName),
        },
        {
          key: "code",
          label: "Mã hiệp hội",
          value: normalizeString(detail.AssociationCode),
        },
        {
          key: "email",
          label: "Email",
          value: detail.Email?.toLowerCase() || "Chưa có thông tin",
        },
        {
          key: "phone",
          label: "Số điện thoại",
          value: normalizeString(detail.PhoneNumber),
        },
        {
          key: "date",
          label: "Ngày tạo",
          value: formatDate(detail.CreateDate),
        },
        {
          key: "address",
          label: "Địa chỉ",
          value: normalizeString(detail.Address),
        },
        {
          key: "type",
          label: "Loại",
          value:
            detail.AssociationType === 1
              ? "Cấp tỉnh"
              : detail.AssociationType === 2
              ? "Cấp huyện"
              : "Chưa xác định",
        },
        {
          key: "status",
          label: "Trạng thái",
          value: statusMap[detail.Status] || statusMap.default,
        },
        ...(detail.Status === 5
          ? [
              {
                key: "rejectReason",
                label: "Lý do từ chối",
                value: normalizeString(detail.RejectReason),
              },
            ]
          : []),
      ]
    : []

  return (
    <CustomModal
      open={open}
      title="Chi tiết hiệp hội"
      width={1100}
      onCancel={onCancel}
      loading={modalLoading}
      footer={
        detail?.Status === 2 && (
          <div className="d-flex justify-content-flex-end" style={{ gap: 10 }}>
            <ButtonCustom
              onClick={handleApprove}
              btnType="primary"
              loading={modalLoading}
            >
              Chấp nhận
            </ButtonCustom>
            <ButtonCustom
              onClick={handleReject}
              btnType="primary"
              danger
              loading={modalLoading}
            >
              Từ chối
            </ButtonCustom>
          </div>
        )
      }
    >
      <div className="association-detail-modal">
        <Row gutter={16}>
          <Col span={9}>
            <div className="info-table-wrapper">
              <table className="info-table">
                <tbody>
                  {infoData.map(item => (
                    <tr key={item.key}>
                      <td className="info-label">{item.label}</td>
                      <td className="info-value">{item.value}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </Col>
          <Col span={15}>
            <div className="member-table-header">
              <div className="member-table-title">
                Danh sách thành viên ({members.length})
              </div>
              <Select
                value={memberType}
                onChange={setMemberType}
                style={{ width: 200 }}
                options={[
                  { label: "Cá nhân", value: 1 },
                  { label: "Doanh nghiệp", value: 2 },
                ]}
              />
            </div>
            <div className="member-table-wrapper">
              <TableCustom
                sticky={{ offsetHeader: -12 }}
                columns={memberColumns}
                dataSource={members.map((item, idx) => ({
                  key: item.MemberID || item.UserID || idx,
                  index: idx,
                  FullName:
                    item.FullName ||
                    item.OrganizationName ||
                    "Chưa có thông tin",
                  PhoneNumber: item.PhoneNumber || "Chưa có thông tin",
                  Identity:
                    item.Identity || item.TaxCode || "Chưa có thông tin",
                  Email: item.Email || "Chưa có thông tin",
                  PositionName: item.PositionName,
                  Position: item.Position,
                  Avatar: item.Avatar,
                  MemberType: item.MemberType,
                }))}
                pagination={false}
                scroll={{ y: 300 }}
                textEmpty="Không có hội viên"
                loading={tableLoading}
              />
            </div>
          </Col>
        </Row>
      </div>

      <Modal
        open={reasonModalOpen}
        title="Lý do từ chối"
        cancelText="Hủy"
        okText="Chấp nhận"
        onCancel={() => {
          setReasonModalOpen(false)
          setRejectReason("")
        }}
        onOk={() => {
          if (!rejectReason.trim()) {
            notice({ msg: "Vui lòng nhập lý do từ chối", isSuccess: false })
            return
          }

          CB1({
            title: "Bạn có chắc chắn muốn từ chối không?",
            icon: "cancel",
            okText: "Đồng ý",
            onOk: async close => {
              try {
                setModalLoading(true)
                const res = await AssociationService.rejectRequest({
                  AssociationIds: [associationId],
                  Reason: rejectReason,
                })
                if (res?.isOk) {
                  notice({ msg: "Từ chối thành công!" })
                  onOk?.()
                  onCancel()
                } else {
                  notice({ msg: "Từ chối thất bại!", isSuccess: false })
                }
              } catch (error) {
                notice({ msg: "Có lỗi khi từ chối!", isSuccess: false })
              } finally {
                setModalLoading(false)
                close()
              }
            },
          })

          setReasonModalOpen(false)
        }}
      >
        <Input.TextArea
          rows={4}
          placeholder="Nhập lý do từ chối..."
          value={rejectReason}
          onChange={e => setRejectReason(e.target.value)}
        />
      </Modal>
    </CustomModal>
  )
}

export default AssociationDetailModal
